// Utilizamos la variable de entorno, si no existe usamos un fallback local
const API_URL = `${process.env.REACT_APP_API_URL || "http://localhost:8080"}/tasks`;

export const getTasks = async (authorId) => {
  const response = await fetch(`${API_URL}?authorId=${authorId}`);
  if (!response.ok) throw new Error("Error al cargar tareas");
  return await response.json();
};

export const createTask = async (taskData, authorId) => {
  const response = await fetch(`${API_URL}?authorId=${authorId}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(taskData),
  });
  if (!response.ok) throw new Error("Error al crear la tarea");
  return await response.json();
};

export const deleteTask = async (taskId) => {
  await fetch(`${API_URL}/${taskId}`, { method: "DELETE" });
};
